const _BY_ID = Object.fromEntries(CURSE_MODELS.map(c => [c.id, c]));
export const getCurse = (id) => _BY_ID[id] || null;
export const cursesByCategory = (cat) => CURSE_MODELS.filter(c => c.categoria === cat);

/** Busca por texto (nome/categoria) + filtro opcional de categoria. */
export function searchCurses(query, categoria) {
  const q = String(query || '').trim().toLowerCase();
  return CURSE_MODELS.filter(c => {
    if (categoria && c.categoria !== categoria) return false;
    if (!q) return true;
    return c.nome.toLowerCase().includes(q) || c.categoria.includes(q);
  });
}
